/*
 * This file was generated by the Gradle 'init' task.
 */

import org.apache.tools.ant.filters.ReplaceTokens
import java.nio.file.Files

plugins {
    id("buildlogic.sbe-conventions")
}

// Exclude stream-protocol.xml from regular resources - we handle it separately for SBE generation
tasks.named<ProcessResources>("processResources") {
    exclude("stream-protocol.xml")
}

// Copy stream-protocol.xml to classes directory (like Maven does) so XInclude paths resolve correctly
val copyStreamProtocol = tasks.register<Copy>("copyStreamProtocol") {
    from("src/main/resources/stream-protocol.xml")
    into(layout.buildDirectory.dir("classes/java/main"))
    // Filter to replace ${project.version} placeholder
    filter(mapOf(
        "tokens" to mapOf("project.version" to project.version.toString()),
        "beginToken" to "\${",
        "endToken" to "}"
    ), ReplaceTokens::class.java)
}

// Create symlink so XInclude relative path resolves correctly
// The XML has: href='../../../protocol/src/main/resources/common-types.xml'
// From build/classes/java/main, this resolves to build/protocol/src/main/resources/
val createProtocolSymlink = tasks.register("createProtocolSymlink") {
    val linkPath = layout.buildDirectory.file("protocol")
    val targetDir = project(":zeebe-protocol").projectDir
    
    inputs.property("targetDir", targetDir.absolutePath)
    // Don't track symlink as output - it points to a directory outside our build
    outputs.upToDateWhen {
        val link = linkPath.get().asFile.toPath()
        Files.isSymbolicLink(link) && Files.readSymbolicLink(link) == targetDir.toPath()
    }
    
    doLast {
        val link = linkPath.get().asFile.toPath()
        val target = targetDir.toPath()
        // Remove existing directory/file if it exists
        if (Files.exists(link)) {
            if (Files.isSymbolicLink(link) && Files.readSymbolicLink(link) == target) {
                return@doLast // Already correct symlink, nothing to do
            }
            if (Files.isSymbolicLink(link)) {
                Files.delete(link)
            } else {
                Files.walk(link).sorted(Comparator.reverseOrder()).forEach { Files.delete(it) }
            }
        }
        link.parent.toFile().mkdirs()
        Files.createSymbolicLink(link, target)
    }
}

// Configure SBE input files for caching
// Include both the stream-protocol.xml and the common-types.xml it references via XInclude
sbe {
    inputFiles.from(
        "src/main/resources/stream-protocol.xml",
        project(":zeebe-protocol").file("src/main/resources/common-types.xml")
    )
}

// Configure SBE generation
tasks.named<JavaExec>("generateSbe") {
    // Use the file from classes directory where XInclude relative paths work correctly
    args(layout.buildDirectory.file("classes/java/main/stream-protocol.xml").get().asFile.absolutePath)
    dependsOn(copyStreamProtocol, createProtocolSymlink)
}

dependencies {
    api(project(":zeebe-atomix-cluster"))
    api(project(":zeebe-atomix-utils"))
    api(project(":zeebe-util"))
    api(project(":zeebe-scheduler"))
    api(libs.org.agrona.agrona)
    api(libs.org.slf4j.slf4j.api)
    testImplementation(project(":zeebe-scheduler"))
    testImplementation(libs.junit.junit)
    testImplementation(libs.org.assertj.assertj.core)
    testImplementation(project(":zeebe-test-util"))
    testImplementation(libs.org.mockito.mockito.core)
    testImplementation(libs.org.junit.jupiter.junit.jupiter.api)
    testImplementation(libs.org.junit.jupiter.junit.jupiter.params)
    testImplementation(libs.org.awaitility.awaitility)
    testImplementation(libs.io.micrometer.micrometer.core)
}

description = "Zeebe Transport"
